const content = $json.choices[0].message.content;
const chatId = $('Config').first().json.chatId;

const cleaned = content
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let promptObj;
try {
  promptObj = JSON.parse(cleaned);
} catch(e) {
  throw new Error('LLM did not return valid JSON. Got: ' + cleaned.slice(0, 300));
}

if (!promptObj.prompt) throw new Error('LLM response missing the "prompt" field');

return [{ json: {
  chatId: String(chatId),
  imagePrompt: JSON.stringify(promptObj)
} }];
